"use strict";(self.webpackChunkastrology_garden=self.webpackChunkastrology_garden||[]).push([["7166"],{7325(e,n,i){i.r(n),i.d(n,{metadata:()=>o,default:()=>p,frontMatter:()=>t,contentTitle:()=>r,toc:()=>c,assets:()=>l});var o=JSON.parse('{"id":"Stellar bodies/moon","title":"moon","description":"THE MOON","source":"@site/docs/Stellar bodies/moon.md","sourceDirName":"Stellar bodies","slug":"/Stellar bodies/moon","permalink":"/docs/Stellar bodies/moon","draft":false,"unlisted":false,"editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/docs/Stellar bodies/moon.md","tags":[],"version":"current","frontMatter":{},"sidebar":"tutorialSidebar","previous":{"title":"mercury","permalink":"/docs/Stellar bodies/mercury"},"next":{"title":"neptune","permalink":"/docs/Stellar bodies/neptune"}}'),a=i(4848),s=i(8453);let t={},r,l={},c=[{value:"T\u0142umaczenie na j\u0119zyk polski (Translation)",id:"t\u0142umaczenie-na-j\u0119zyk-polski-translation",level:3}];function d(e){let n={h3:"h3",li:"li",p:"p",ul:"ul",...(0,s.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(n.p,{children:"THE MOON"}),"\n",(0,a.jsx)(n.p,{children:"Principle:"}),"\n",(0,a.jsx)(n.p,{children:"Soul, the female principle."}),"\n",(0,a.jsx)(n.p,{children:"Psychological Correspondence:"}),"\n",(0,a.jsxs)(n.ul,{children:["\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"Motherliness, domesticity, prudence, mobility, changeableness, adaptation, sense of form, memory."}),"\n"]}),"\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"Repressed motherliness, love of comfort, impressionability, a care-free attitude or an easy-going nature, moodiness."}),"\n"]}),"\n"]}),"\n",(0,a.jsx)(n.p,{children:"Biological Correspondence:"}),"\n",(0,a.jsx)(n.p,{children:"Fertility, the bodily fluids, blood-serum, the lymph (cerebellum)."}),"\n",(0,a.jsx)(n.p,{children:"Sociological Correspondence:"}),"\n",(0,a.jsx)(n.p,{children:"The mother, the spouse, the wife, the family, the nation, hereditary qualities or traits as a whole."}),"\n",(0,a.jsx)(n.p,{children:"Position in Houses and Signs:"}),"\n",(0,a.jsx)(n.p,{children:"I. The will is influenced by feeling (an impulsive nature), impulsiveness, over-eagerness. \u2013 Hastiness or rashness, acting without thinking, arguments, the lust for power. \u2013 A strong personality."}),"\n",(0,a.jsx)(n.p,{children:"II. Constancy, tenacious clinging to acquired possessions, steadfastness and firmness, an understanding or appreciation of the beautiful, enjoyment of life. \u2013 Pronounced growth of tissue. \u2013 Changeable material circumstances."}),"\n",(0,a.jsx)(n.p,{children:"III. Manifold and vivid powers of expression with regard to feelings and sentiments, changes of mood, mental and physical mobility, many-sided interests, abundant wishing and hoping, easy despondency, superficiality. \u2013 Many ups and downs, changes, associations."}),"\n",(0,a.jsx)(n.p,{children:"IV. Emotional strength, an affectionate nature, family-spirit, domesticity, simplicity, economy, impressionability. \u2013 Interrelationship between the emotional state and the digestive organs (stomach). \u2013 Family-matters."}),"\n",(0,a.jsx)(n.p,{children:'V. Intuitive and instinctive creativeness, self-confidence, generosity, ambition, passionateness, love of luxury, sociability, pleasure or amusement. \u2013 Overestimation of self, snobbishness, vanity. \u2013 "The affairs of the heart", responsible positions.'}),"\n",(0,a.jsx)(n.p,{children:"VI. The head rules the heart, practical consideration, methodical procedure, diligence and care, love of tidiness, correct behaviour, simplicity. \u2013 Pedantry. \u2013 Practical outlook on life."}),"\n",(0,a.jsx)(n.p,{children:"VII. Vivid expression of the feelings, obligingness, the need for love and affection, dependence on the partner, sociableness. \u2013 Self-indulgence, lack of responsibility, the stress on unimportant things. Fateful partnerships."}),"\n",(0,a.jsx)(n.p,{children:"VIII. Fighting spirit influenced by emotional stirrings, toughness or tenacity, ambition, ruthlessness, overestimation of self, lack of tact, frankness, love of truth. \u2013 The struggle for existence or the fight for survival."}),"\n",(0,a.jsx)(n.p,{children:"IX. A vivid inner life, changing moods, inconstancy, a striving for wisdom, idealistic thoughts as guides to action, optimism and pessimism alternate in phases. A life full of changes."}),"\n",(0,a.jsx)(n.p,{children:"X. A repressed emotional life, little expression of one's own feelings, endurance, patience, a sense of duty, awareness of responsibility, a sober and practical outlook on life. \u2013 Deep interest in profession."}),"\n",(0,a.jsx)(n.p,{children:"XI. Wealth of ideas, deep concern for other people's troubles, good powers of observation, understanding and sympathetic nature, the ability to change, readiness to help others, love of independence, abundant hopes and wishes."}),"\n",(0,a.jsx)(n.p,{children:"XII. Susceptibility to external influences, subject to moods, a hopeful or optimistic state of mind, the danger of unconditional yielding or drifting, a feeling of inferiority, the danger of exploitation or drift."}),"\n",(0,a.jsx)(n.h3,{id:"t\u0142umaczenie-na-j\u0119zyk-polski-translation",children:"T\u0142umaczenie na j\u0119zyk polski (Translation)"}),"\n",(0,a.jsx)(n.p,{children:"Zasada:"}),"\n",(0,a.jsx)(n.p,{children:"Dusza, pierwiastek \u017Ce\u0144ski."}),"\n",(0,a.jsx)(n.p,{children:"Korespondencja psychologiczna:"}),"\n",(0,a.jsxs)(n.ul,{children:["\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"Macierzy\u0144sko\u015B\u0107, przywi\u0105zanie do ogniska domowego, roztropno\u015B\u0107, mobilno\u015B\u0107, zmienno\u015B\u0107, zdolno\u015B\u0107 adaptacji, zmys\u0142 formy, pami\u0119\u0107."}),"\n"]}),"\n",(0,a.jsxs)(n.li,{children:["\n",(0,a.jsx)(n.p,{children:"St\u0142umiona macierzy\u0144sko\u015B\u0107, zami\u0142owanie do wygody, podatno\u015B\u0107 na wra\u017Cenia, beztroska postawa lub \u0142atwowierny/wyluzowany charakter, humorzasto\u015B\u0107."}),"\n"]}),"\n"]}),"\n",(0,a.jsx)(n.p,{children:"Korespondencja biologiczna:"}),"\n",(0,a.jsx)(n.p,{children:"P\u0142odno\u015B\u0107, p\u0142yny ustrojowe, surowica krwi, limfa (m\xf3\u017Cd\u017Cek)."}),"\n",(0,a.jsx)(n.p,{children:"Korespondencja socjologiczna:"}),"\n",(0,a.jsx)(n.p,{children:"Matka, ma\u0142\u017Conek, \u017Cona, rodzina, nar\xf3d, cechy lub przymioty dziedziczne jako ca\u0142o\u015B\u0107."}),"\n",(0,a.jsx)(n.p,{children:"Pozycja w domach i znakach:"}),"\n",(0,a.jsx)(n.p,{children:"I. Wola jest pod wp\u0142ywem uczu\u0107 (impulsywna natura), impulsywno\u015B\u0107, nadgorliwo\u015B\u0107. \u2013 Po\u015Bpiech lub lekkomy\u015Blno\u015B\u0107, dzia\u0142anie bez zastanowienia, k\u0142\xf3tnie, \u017C\u0105dza w\u0142adzy. \u2013 Silna osobowo\u015B\u0107."}),"\n",(0,a.jsx)(n.p,{children:"II. Sta\u0142o\u015B\u0107, nieust\u0119pliwe trzymanie si\u0119 zdobytych posiad\u0142o\u015Bci, niez\u0142omno\u015B\u0107 i stanowczo\u015B\u0107, rozumienie lub docenianie pi\u0119kna, czerpanie rado\u015Bci z \u017Cycia. \u2013 Wyra\u017Any wzrost tkanki. \u2013 Zmienne warunki materialne."}),"\n",(0,a.jsx)(n.p,{children:"III. R\xf3\u017Cnorodne i \u017Cywe zdolno\u015Bci wyra\u017Cania uczu\u0107 i nastroj\xf3w, zmiany nastroju, psychiczna i fizyczna mobilno\u015B\u0107, wszechstronne zainteresowania, obfito\u015B\u0107 \u017Cycze\u0144 i nadziei, \u0142atwe przygn\u0119bienie, powierzchowno\u015B\u0107. \u2013 Wiele wzlot\xf3w i upadk\xf3w, zmiany, zwi\u0105zki."}),"\n",(0,a.jsx)(n.p,{children:"IV. Si\u0142a emocjonalna, czu\u0142a natura, duch rodzinny, przywi\u0105zanie do ogniska domowego, prostota, oszcz\u0119dno\u015B\u0107, podatno\u015B\u0107 na wra\u017Cenia. \u2013 Wzajemna zale\u017Cno\u015B\u0107 mi\u0119dzy stanem emocjonalnym a narz\u0105dami trawiennymi (\u017Co\u0142\u0105dkiem). \u2013 Sprawy rodzinne."}),"\n",(0,a.jsx)(n.p,{children:"V. Intuicyjna i instynktowna kreatywno\u015B\u0107, pewno\u015B\u0107 siebie, wielkoduszno\u015B\u0107, ambicja, nami\u0119tno\u015B\u0107, zami\u0142owanie do luksusu, towarzysko\u015B\u0107, przyjemno\u015B\u0107 lub rozrywka. \u2013 Przecenianie samego siebie, snobizm, pr\xf3\u017Cno\u015B\u0107. \u2013 \u201ESprawy sercowe\u201D, odpowiedzialne stanowiska."}),"\n",(0,a.jsx)(n.p,{children:"VI. G\u0142owa rz\u0105dzi sercem, praktyczne wzgl\u0119dy, metodyczne post\u0119powanie, pilno\u015B\u0107 i troska, zami\u0142owanie do porz\u0105dku, poprawne zachowanie, prostota. \u2013 Pedanteria. \u2013 Praktyczne spojrzenie na \u017Cycie."}),"\n",(0,a.jsx)(n.p,{children:"VII. \u017Bywe wyra\u017Canie uczu\u0107, uczynno\u015B\u0107, potrzeba mi\u0142o\u015Bci i czu\u0142o\u015Bci, zale\u017Cno\u015B\u0107 od partnera, towarzysko\u015B\u0107. \u2013 Pob\u0142a\u017Canie sobie, brak odpowiedzialno\u015Bci, k\u0142adzenie nacisku na rzeczy nieistotne. Fatalne (b\u0119d\u0105ce zrz\u0105dzeniem losu) partnerstwa."}),"\n",(0,a.jsx)(n.p,{children:"VIII. Duch walki pod wp\u0142ywem emocjonalnych porusze\u0144, twardo\u015B\u0107 lub nieust\u0119pliwo\u015B\u0107, ambicja, bezwzgl\u0119dno\u015B\u0107, przecenianie samego siebie, brak taktu, szczero\u015B\u0107, zami\u0142owanie do prawdy. \u2013 Walka o byt lub walka o przetrwanie."}),"\n",(0,a.jsx)(n.p,{children:"IX. \u017Bywe \u017Cycie wewn\u0119trzne, zmieniaj\u0105ce si\u0119 nastroje, niesta\u0142o\u015B\u0107, d\u0105\u017Cenie do m\u0105dro\u015Bci, idealistyczne my\u015Bli jako przewodniki w dzia\u0142aniu, optymizm i pesymizm przeplataj\u0105ce si\u0119 fazami. \u017Bycie pe\u0142ne zmian."}),"\n",(0,a.jsx)(n.p,{children:"X. St\u0142umione \u017Cycie emocjonalne, s\u0142abe wyra\u017Canie w\u0142asnych uczu\u0107, wytrzyma\u0142o\u015B\u0107, cierpliwo\u015B\u0107, poczucie obowi\u0105zku, \u015Bwiadomo\u015B\u0107 odpowiedzialno\u015Bci, trze\u017Awe i praktyczne spojrzenie na \u017Cycie. \u2013 G\u0142\u0119bokie zainteresowanie profesj\u0105 (zawodem)."}),"\n",(0,a.jsx)(n.p,{children:"XI. Bogactwo pomys\u0142\xf3w, g\u0142\u0119boka troska o problemy innych ludzi, dobra zdolno\u015B\u0107 obserwacji, wyrozumia\u0142a i pe\u0142na empatii natura, zdolno\u015B\u0107 do zmian, gotowo\u015B\u0107 do pomagania innym, zami\u0142owanie do niezale\u017Cno\u015Bci, obfite nadzieje i \u017Cyczenia."}),"\n",(0,a.jsx)(n.p,{children:"XII. Podatno\u015B\u0107 na wp\u0142ywy zewn\u0119trzne, uleganie nastrojom, pe\u0142en nadziei lub optymistyczny stan umys\u0142u, niebezpiecze\u0144stwo bezwarunkowego ulegania lub dryfowania, poczucie ni\u017Cszo\u015Bci, niebezpiecze\u0144stwo wyzysku lub dryfowania."})]})}function p(e={}){let{wrapper:n}={...(0,s.R)(),...e.components};return n?(0,a.jsx)(n,{...e,children:(0,a.jsx)(d,{...e})}):d(e)}},8453(e,n,i){i.d(n,{R:()=>t,x:()=>r});var o=i(6540);let a={},s=o.createContext(a);function t(e){let n=o.useContext(s);return o.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function r(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:t(e.components),o.createElement(s.Provider,{value:n},e.children)}}}]);